import './Counter.scss';

import React, { forwardRef } from 'react';

import { Tooltip } from '../Tooltip';
import type { CounterProps } from './Counter.types';
import { CounterBody } from './CounterBody';

export const Counter = forwardRef<HTMLDivElement, CounterProps>(({ tooltipTitle = '', ...rest }, ref) => {
	const counterBody = <CounterBody data-testid="Counter" {...rest} ref={ref} />;

	return (
		<>
			{tooltipTitle && <Tooltip title={tooltipTitle}>{counterBody}</Tooltip>}
			{!tooltipTitle && counterBody}
		</>
	);
});
